"use client";

import React, { useMemo, useState } from "react";
import { Card, Button, Badge, Input } from "@/components/marketing/ui";
import type { ExamResult } from "@/components/marketing/ExamCertificate";
import {
  ATTEMPT_CSV_HEADER,
  attemptToCsvRow,
  SKILL_BANDS,
  type AttemptSummary,
} from "@/lib/marketing-tests/exams";

function toSummary(r: ExamResult): AttemptSummary {
  return {
    attemptId: r.attemptId,
    examId: r.examId,
    examTitle: r.examTitle,
    domain: r.domain,
    candidate: r.candidate,
    email: r.email,
    percentage: r.percentage,
    weightedPercentage: r.percentage,
    band: r.band.band,
    passed: r.passed,
    elapsedSeconds: r.elapsedSeconds,
    timedOut: r.timedOut,
    tabSwitches: r.tabSwitches,
    takenAt: r.takenAt,
  };
}

function download(filename: string, content: string, mime: string): void {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

function formatDuration(totalSeconds: number): string {
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}m ${seconds.toString().padStart(2, "0")}s`;
}

function formatLocalDate(epochMs: number): string {
  return new Date(epochMs).toLocaleDateString(undefined, {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

function bandRank(band: string): number {
  const idx = SKILL_BANDS.findIndex((b) => b.band === band);
  return idx === -1 ? 0 : idx;
}

interface CandidateProfile {
  candidate: string;
  attempts: number;
  exams: string[];
  averagePercentage: number;
  bestBand: string;
  passRate: number;
}

function buildProfiles(history: ExamResult[]): CandidateProfile[] {
  const map = new Map<string, ExamResult[]>();
  for (const r of history) {
    const arr = map.get(r.candidate);
    if (arr) {
      arr.push(r);
    } else {
      map.set(r.candidate, [r]);
    }
  }
  const profiles: CandidateProfile[] = [];
  for (const [candidate, attempts] of map) {
    const exams = Array.from(
      new Set(attempts.map((a) => a.examTitle)),
    );
    const averagePercentage =
      attempts.reduce((sum, a) => sum + a.percentage, 0) / attempts.length;
    let bestBand = attempts[0]!.band.band;
    let bestRank = bandRank(bestBand);
    for (const a of attempts) {
      const rank = bandRank(a.band.band);
      if (rank > bestRank) {
        bestRank = rank;
        bestBand = a.band.band;
      }
    }
    const passed = attempts.filter((a) => a.passed).length;
    const passRate = (passed / attempts.length) * 100;
    profiles.push({
      candidate,
      attempts: attempts.length,
      exams,
      averagePercentage,
      bestBand,
      passRate,
    });
  }
  profiles.sort((a, b) => b.averagePercentage - a.averagePercentage);
  return profiles;
}

export function RecruiterCompare({
  history,
  onBack,
  onViewAttempt,
}: {
  history: ExamResult[];
  onBack: () => void;
  onViewAttempt: (attempt: ExamResult) => void;
}) {
  const [examFilter, setExamFilter] = useState<string>("all");
  const [search, setSearch] = useState<string>("");

  const examIds = useMemo(() => {
    const seen = new Set<string>();
    const ids: { id: string; title: string }[] = [];
    for (const r of history) {
      if (!seen.has(r.examId)) {
        seen.add(r.examId);
        ids.push({ id: r.examId, title: r.examTitle });
      }
    }
    return ids;
  }, [history]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    return history.filter((r) => {
      if (examFilter !== "all" && r.examId !== examFilter) return false;
      if (q && !r.candidate.toLowerCase().includes(q)) return false;
      return true;
    });
  }, [history, examFilter, search]);

  const profiles = useMemo(() => buildProfiles(filtered), [filtered]);

  const topPerformer = useMemo(() => {
    if (profiles.length === 0) return null;
    return profiles[0]!.candidate;
  }, [profiles]);

  const handleExportCsv = () => {
    const rows = filtered.map((r) => attemptToCsvRow(toSummary(r)));
    const csv = [ATTEMPT_CSV_HEADER, ...rows].join("\n");
    download("recruiter-attempts.csv", csv, "text/csv;charset=utf-8");
  };

  const handleExportJson = () => {
    const json = JSON.stringify(filtered, null, 2);
    download("recruiter-attempts.json", json, "application/json");
  };

  if (history.length === 0) {
    return (
      <Card className="p-8 text-center">
        <div className="mx-auto flex max-w-md flex-col items-center gap-3">
          <div className="flex h-14 w-14 items-center justify-center rounded-full bg-gray-100 text-2xl">
            📊
          </div>
          <h2 className="text-lg font-bold text-gray-900">
            No attempts to compare yet.
          </h2>
          <p className="text-sm text-gray-500">
            Once candidates complete marketing exams, their results will appear
            here for side-by-side comparison.
          </p>
          <Button variant="outline" className="mt-2" onClick={onBack}>
            Back to exams
          </Button>
        </div>
      </Card>
    );
  }

  return (
    <div className="flex flex-col gap-6">
      <div className="flex items-center justify-between gap-4">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold text-gray-900">
            Recruiter Comparison Dashboard
          </h1>
          <p className="text-sm text-gray-500">
            Compare candidates across all stored marketing exam attempts.
          </p>
        </div>
        <Button variant="outline" onClick={onBack}>
          Back to exams
        </Button>
      </div>

      <Card className="p-4">
        <div className="flex flex-col gap-4">
          <div className="flex flex-wrap items-center gap-2">
            <span className="text-xs font-semibold uppercase tracking-wide text-gray-500">
              Exam:
            </span>
            <Button
              variant={examFilter === "all" ? "default" : "outline"}
              onClick={() => setExamFilter("all")}
            >
              All
            </Button>
            {examIds.map((e) => (
              <Button
                key={e.id}
                variant={examFilter === e.id ? "default" : "outline"}
                onClick={() => setExamFilter(e.id)}
              >
                {e.title}
              </Button>
            ))}
          </div>
          <div className="flex flex-1 items-center gap-3">
            <Input
              placeholder="Search candidates by name…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="max-w-sm"
            />
            <div className="ml-auto flex gap-2">
              <Button variant="secondary" onClick={handleExportCsv}>
                Export CSV
              </Button>
              <Button variant="secondary" onClick={handleExportJson}>
                Export JSON
              </Button>
            </div>
          </div>
        </div>
      </Card>

      <Card className="overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-2 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Candidate
                </th>
                <th className="px-4 py-2 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Exam
                </th>
                <th className="px-4 py-2 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Date
                </th>
                <th className="px-4 py-2 text-right text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Score %
                </th>
                <th className="px-4 py-2 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Band
                </th>
                <th className="px-4 py-2 text-right text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Duration
                </th>
                <th className="px-4 py-2 text-right text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Tab switches
                </th>
                <th className="px-4 py-2 text-center text-xs font-semibold uppercase tracking-wide text-gray-500">
                  Result
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filtered.length === 0 ? (
                <tr>
                  <td
                    colSpan={8}
                    className="px-4 py-8 text-center text-sm text-gray-500"
                  >
                    No attempts match the current filters.
                  </td>
                </tr>
              ) : (
                filtered.map((r) => (
                  <tr
                    key={r.attemptId}
                    className="cursor-pointer bg-white hover:bg-indigo-50"
                    onClick={() => onViewAttempt(r)}
                  >
                    <td className="px-4 py-2 font-medium text-gray-900">
                      {r.candidate}
                    </td>
                    <td className="px-4 py-2 text-gray-600">{r.examTitle}</td>
                    <td className="px-4 py-2 text-gray-600">
                      {formatLocalDate(r.takenAt)}
                    </td>
                    <td className="px-4 py-2 text-right text-gray-900">
                      {r.percentage}%
                    </td>
                    <td className="px-4 py-2">
                      <Badge variant="secondary">{r.band.band}</Badge>
                    </td>
                    <td className="px-4 py-2 text-right text-gray-600">
                      {formatDuration(r.elapsedSeconds)}
                    </td>
                    <td className="px-4 py-2 text-right text-gray-600">
                      {r.tabSwitches}
                    </td>
                    <td className="px-4 py-2 text-center">
                      {r.passed ? (
                        <Badge
                          variant="default"
                          className="bg-green-100 text-green-700 border-green-200"
                        >
                          PASS
                        </Badge>
                      ) : (
                        <Badge variant="destructive">FAIL</Badge>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </Card>

      {profiles.length > 0 && (
        <Card className="p-4">
          <h2 className="mb-3 text-sm font-bold uppercase tracking-wide text-gray-700">
            Candidate Profiles
          </h2>
          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-3">
            {profiles.map((p) => {
              const isTop = p.candidate === topPerformer;
              return (
                <Card
                  key={p.candidate}
                  className={
                    isTop
                      ? "border-2 border-amber-300 bg-amber-50 p-4"
                      : "p-4"
                  }
                >
                  <div className="mb-2 flex items-center justify-between gap-2">
                    <span className="font-semibold text-gray-900">
                      {p.candidate}
                    </span>
                    {isTop && (
                      <Badge className="bg-amber-200 text-amber-800 border-amber-300">
                        ★ Top Performer
                      </Badge>
                    )}
                  </div>
                  <dl className="grid grid-cols-2 gap-y-1 text-xs text-gray-600">
                    <dt className="font-medium text-gray-500">Attempts</dt>
                    <dd className="text-right text-gray-900">{p.attempts}</dd>
                    <dt className="font-medium text-gray-500">Exams taken</dt>
                    <dd className="text-right text-gray-900">{p.exams.length}</dd>
                    <dt className="font-medium text-gray-500">Avg score</dt>
                    <dd className="text-right text-gray-900">
                      {p.averagePercentage.toFixed(1)}%
                    </dd>
                    <dt className="font-medium text-gray-500">Best band</dt>
                    <dd className="text-right text-gray-900">{p.bestBand}</dd>
                    <dt className="font-medium text-gray-500">Pass rate</dt>
                    <dd className="text-right text-gray-900">
                      {p.passRate.toFixed(0)}%
                    </dd>
                  </dl>
                </Card>
              );
            })}
          </div>
        </Card>
      )}
    </div>
  );
}

